import ClubOverview from "./ClubOverview";
import ClubNews from "./ClubNews";
import ClubMembers from "./ClubMembers";
import ClubStats from "./ClubStats";

export default function ClubMain({
                                     tab,
                                     club,
                                     members,
                                     news,
                                     isLeader,
                                     user
                                 }) {
    const TAB_MAP = {
        overview: ClubOverview,
        news: ClubNews,
        members: ClubMembers,
        stats: ClubStats
    };

    // Club-specific tab control
    const enabledTabs = club.enabledTabs || ["overview", "news", "members"];

    if (!enabledTabs.includes(tab)) {
        return <div style={{ padding: 20 }}>Tab not available for this club.</div>;
    }

    const ActiveTab = TAB_MAP[tab] || ClubOverview;

    return (
        <div style={{ padding: 20 }}>
            <ActiveTab
                club={club}
                members={members}
                news={news}
                isLeader={isLeader}
                user={user}
            />
        </div>
    );
}
